import math

class ShapeCalculator:
    @classmethod
    def circle_area(cls, radius):
        return math.pi * radius ** 2

    @classmethod
    def square_area(cls, side):
        return side ** 2

    @classmethod
    def triangle_area(cls, base, height):
        return 0.5 * base * height

if __name__ == "__main__":
    shape, *params = input().split()
    params = list(map(float, params))

    if shape == "circle":
        result = ShapeCalculator.circle_area(params[0])
    elif shape == "square":
        result = ShapeCalculator.square_area(params[0])
    elif shape == "triangle":
        result = ShapeCalculator.triangle_area(params[0], params[1])

    print(f"{result:.2f}")
